import { useEffect, useState } from "react";
import { addProduct, deleteProduct, getProducts, updateProduct } from "../services/api";
import "../css/Products.css";

const initialForm = {
  name: "",
  category: "",
  price: "",
  stockQuantity: "",
  image: null,
};

function Products() {
  const [products, setProducts] = useState([]);
  const [formData, setFormData] = useState(initialForm);
  const [editingId, setEditingId] = useState("");
  const [message, setMessage] = useState("");
  const [messageType, setMessageType] = useState("success");

  const loadProducts = async () => {
    try {
      const response = await getProducts();
      setProducts(response.data || []);
    } catch (error) {
      setProducts([]);
    }
  };

  useEffect(() => {
    loadProducts();
  }, []);

  const handleChange = (event) => {
    const { name, value, files } = event.target;
    if (name === "image") {
      setFormData((prev) => ({ ...prev, image: files[0] || null }));
      return;
    }
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const resetForm = () => {
    setFormData(initialForm);
    setEditingId("");
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setMessage("");

    const payload = new FormData();
    payload.append("name", formData.name);
    payload.append("category", formData.category);
    payload.append("price", formData.price);
    payload.append("stockQuantity", formData.stockQuantity);
    if (formData.image) {
      payload.append("image", formData.image);
    }

    try {
      if (editingId) {
        await updateProduct(editingId, payload);
        setMessage("Product updated successfully.");
      } else {
        await addProduct(payload);
        setMessage("Product added successfully.");
      }
      setMessageType("success");
      resetForm();
      loadProducts();
    } catch (error) {
      setMessageType("danger");
      setMessage(error.response?.data?.message || "Failed to save product.");
    }
  };

  const handleEdit = (product) => {
    setEditingId(product._id);
    setFormData({
      name: product.name,
      category: product.category,
      price: product.price,
      stockQuantity: product.stockQuantity,
      image: null,
    });
  };

  const handleDelete = async (id) => {
    try {
      await deleteProduct(id);
      setMessageType("success");
      setMessage("Product deleted successfully.");
      loadProducts();
    } catch (error) {
      setMessageType("danger");
      setMessage(error.response?.data?.message || "Failed to delete product.");
    }
  };

  return (
    <section className="products-page">
      <div className="container-fluid">
        <div className="products-header mb-4">
          <h2 className="products-title">Product Management</h2>
          <p className="products-subtitle">Add, edit, and track stock with product images.</p>
        </div>

        <div className="card border-0 shadow-sm products-form-card mb-4">
          <div className="card-body">
            {message ? <div className={`alert alert-${messageType}`}>{message}</div> : null}
            <form className="row g-3" onSubmit={handleSubmit}>
              <div className="col-md-3">
                <label className="form-label">Product Name</label>
                <input
                  type="text"
                  name="name"
                  className="form-control"
                  value={formData.name}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Category</label>
                <input
                  type="text"
                  name="category"
                  className="form-control"
                  value={formData.category}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Price</label>
                <input
                  type="number"
                  min="0"
                  name="price"
                  className="form-control"
                  value={formData.price}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-2">
                <label className="form-label">Stock Qty</label>
                <input
                  type="number"
                  min="0"
                  name="stockQuantity"
                  className="form-control"
                  value={formData.stockQuantity}
                  onChange={handleChange}
                  required
                />
              </div>
              <div className="col-md-3">
                <label className="form-label">Image</label>
                <input type="file" name="image" className="form-control" onChange={handleChange} />
              </div>
              <div className="col-12 d-flex gap-2">
                <button type="submit" className="btn btn-primary">
                  {editingId ? "Update Product" : "Add Product"}
                </button>
                <button type="button" className="btn btn-outline-secondary" onClick={resetForm}>
                  Reset
                </button>
              </div>
            </form>
          </div>
        </div>

        <div className="card border-0 shadow-sm">
          <div className="card-body">
            <div className="table-responsive">
              <table className="table align-middle products-table">
                <thead>
                  <tr>
                    <th>Image</th>
                    <th>Name</th>
                    <th>Category</th>
                    <th>Price</th>
                    <th>Stock</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {products.length ? (
                    products.map((product) => (
                      <tr key={product._id}>
                        <td>
                          {product.image ? (
                            <img
                              src={`http://localhost:5000/${product.image}`}
                              alt={product.name}
                              className="product-thumb"
                            />
                          ) : (
                            <span className="no-image">No Image</span>
                          )}
                        </td>
                        <td>{product.name}</td>
                        <td>{product.category}</td>
                        <td>Rs {Number(product.price).toLocaleString("en-IN")}</td>
                        <td>
                          <span className={product.stockQuantity <= 5 ? "stock-low" : "stock-normal"}>
                            {product.stockQuantity}
                          </span>
                        </td>
                        <td>
                          <div className="d-flex gap-2">
                            <button type="button" className="btn btn-sm btn-outline-primary" onClick={() => handleEdit(product)}>
                              Edit
                            </button>
                            <button type="button" className="btn btn-sm btn-outline-danger" onClick={() => handleDelete(product._id)}>
                              Delete
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan="6" className="text-center py-4">
                        No products found.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default Products;
